"use client";

import { useMemo, useState } from "react";
import {
  PieChart,
  Pie,
  Cell,
  BarChart,
  Bar,
  XAxis,
  YAxis,
  Tooltip,
  ResponsiveContainer,
} from "recharts";
import { ChartPie, CaretDown, CaretUp } from "@phosphor-icons/react";
import { TAG_COLOR_HEX, type TagColor } from "@/lib/tag-colors";
import { getRatingLabel } from "@/lib/rating-labels";

type TagInfo = {
  id: string;
  name: string;
  color: string;
};

type ListAnalyticsProps = {
  items: { id: string; rating: number | null; shows: { id: string } }[];
  showTagsMap: Record<string, string[]>;
  allTags: TagInfo[];
  ratingLabels?: string[] | null;
  labels: {
    analytics: string;
    tagDistribution: string;
    ratingDistribution: string;
    noTags: string;
    noRatings: string;
    shows: string;
    unrated: string;
  };
};

const RATING_BAR_COLOR = "#00d4aa";

export function ListAnalytics({
  items,
  showTagsMap,
  allTags,
  ratingLabels,
  labels,
}: ListAnalyticsProps) {
  const [open, setOpen] = useState(false);

  // --- Tag pie data ---
  const tagData = useMemo(() => {
    const counts: Record<string, number> = {};
    for (const item of items) {
      const tagIds = showTagsMap[item.shows.id] ?? [];
      for (const tagId of tagIds) {
        counts[tagId] = (counts[tagId] ?? 0) + 1;
      }
    }
    const tagMap = new Map(allTags.map((t) => [t.id, t]));
    return Object.entries(counts)
      .map(([tagId, count]) => {
        const tag = tagMap.get(tagId);
        if (!tag) return null;
        return {
          name: tag.name,
          value: count,
          color: TAG_COLOR_HEX[tag.color as TagColor] ?? TAG_COLOR_HEX.slate,
        };
      })
      .filter(Boolean)
      .sort((a, b) => b!.value - a!.value) as {
      name: string;
      value: number;
      color: string;
    }[];
  }, [items, showTagsMap, allTags]);

  // --- Rating histogram data ---
  const ratingData = useMemo(() => {
    const counts: Record<string, number> = {};
    for (let r = 1; r <= 10; r++) counts[r] = 0;
    for (const item of items) {
      if (item.rating !== null && item.rating >= 1 && item.rating <= 10) {
        counts[item.rating]++;
      }
    }
    return Array.from({ length: 10 }, (_, i) => {
      const rating = i + 1;
      return {
        rating,
        label: getRatingLabel(rating, ratingLabels),
        count: counts[rating],
      };
    });
  }, [items, ratingLabels]);

  const hasTagData = tagData.length > 0;
  const hasRatingData = ratingData.some((d) => d.count > 0);

  if (items.length === 0) return null;

  return (
    <div className="mb-6">
      <button
        onClick={() => setOpen((v) => !v)}
        className="flex w-full items-center gap-2 rounded-md border border-border px-3 py-2 text-xs font-medium text-text-secondary transition-colors hover:border-border-hover hover:text-text-primary"
      >
        <ChartPie size={14} />
        {labels.analytics}
        {open ? (
          <CaretUp size={12} className="ml-auto" />
        ) : (
          <CaretDown size={12} className="ml-auto" />
        )}
      </button>

      {open && (
        <div className="mt-3 grid gap-6 sm:grid-cols-2">
          {/* Tag distribution pie chart */}
          <div className="rounded-lg border border-border bg-bg-surface p-4">
            <h3 className="mb-3 text-xs font-semibold uppercase tracking-widest text-text-faint">
              {labels.tagDistribution}
            </h3>
            {hasTagData ? (
              <div className="flex flex-col items-center gap-3">
                <ResponsiveContainer width="100%" height={200}>
                  <PieChart>
                    <Pie
                      data={tagData}
                      dataKey="value"
                      nameKey="name"
                      cx="50%"
                      cy="50%"
                      innerRadius={45}
                      outerRadius={80}
                      paddingAngle={2}
                      stroke="none"
                    >
                      {tagData.map((entry, idx) => (
                        <Cell key={idx} fill={entry.color} />
                      ))}
                    </Pie>
                    <Tooltip
                      contentStyle={{
                        backgroundColor: "var(--bg-elevated)",
                        border: "1px solid var(--border)",
                        borderRadius: "var(--radius-md)",
                        fontSize: "12px",
                        color: "var(--text-primary)",
                      }}
                      formatter={(value) => [
                        `${value} ${labels.shows}`,
                      ]}
                    />
                  </PieChart>
                </ResponsiveContainer>
                {/* Legend */}
                <div className="flex flex-wrap justify-center gap-x-3 gap-y-1">
                  {tagData.map((entry) => (
                    <div
                      key={entry.name}
                      className="flex items-center gap-1.5 text-[11px] text-text-secondary"
                    >
                      <span
                        className="inline-block h-2 w-2 rounded-full"
                        style={{ backgroundColor: entry.color }}
                      />
                      {entry.name}{" "}
                      <span className="font-mono text-text-muted">
                        {entry.value}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            ) : (
              <p className="py-8 text-center text-xs text-text-muted">
                {labels.noTags}
              </p>
            )}
          </div>

          {/* Rating distribution bar chart */}
          <div className="rounded-lg border border-border bg-bg-surface p-4">
            <h3 className="mb-3 text-xs font-semibold uppercase tracking-widest text-text-faint">
              {labels.ratingDistribution}
            </h3>
            {hasRatingData ? (
              <ResponsiveContainer width="100%" height={200}>
                <BarChart
                  data={ratingData}
                  margin={{ top: 4, right: 4, bottom: 0, left: -20 }}
                >
                  <XAxis
                    dataKey="rating"
                    tick={{ fontSize: 11, fill: "var(--text-muted)" }}
                    tickLine={false}
                    axisLine={{ stroke: "var(--border)" }}
                  />
                  <YAxis
                    allowDecimals={false}
                    tick={{ fontSize: 11, fill: "var(--text-muted)" }}
                    tickLine={false}
                    axisLine={false}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: "var(--bg-elevated)",
                      border: "1px solid var(--border)",
                      borderRadius: "var(--radius-md)",
                      fontSize: "12px",
                      color: "var(--text-primary)",
                    }}
                    formatter={(value, _name, props) => [
                      `${value} ${labels.shows}`,
                      (props as { payload?: { label?: string } })?.payload?.label ?? '',
                    ]}
                    labelFormatter={(rating) => `${rating}/10`}
                  />
                  <Bar
                    dataKey="count"
                    fill={RATING_BAR_COLOR}
                    radius={[3, 3, 0, 0]}
                    maxBarSize={40}
                  />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <p className="py-8 text-center text-xs text-text-muted">
                {labels.noRatings}
              </p>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
